# agentic_I2 skeptic-crosscheck · S16-T1-A-E2
import pandas as pd
policy = {"a": "required", "b": "optional"}
df = pd.DataFrame({"a": [1, None], "b": [None, 2]})
viol = {c: int(df[c].isna().sum()) for c, p in policy.items() if p == "required" and df[c].isna().any()}
print(viol)

# agentic_I2 skeptic-crosscheck · S16-T2-A-E3
import pandas as pd
df = pd.DataFrame({"cliente_id": ["C001"], "area": ["Lima"], "score": [1.0]})
sub = df[df.cliente_id == "C001"]
if sub.duplicated(keep=False).any() and sub.duplicated(keep=False).all():
    print("exact")
elif sub["area"].nunique() > 1:
    print("conflict")
else:
    print("clean")
